mapper.select:
SELECT id, user_id, position, round, difficulty, question_count, current_question,
       question_ids, status, created_at, updated_at
FROM interview_session WHERE id = #{id}

SELECT s.id, s.user_id, s.position, s.round, s.difficulty, s.question_count,
       s.current_question, s.question_ids, s.status, s.created_at, s.updated_at,
       r.total_score, r.level, r.created_at AS report_created_at
FROM interview_session s
LEFT JOIN interview_report r ON s.id = r.session_id
WHERE s.user_id = #{userId}

    AND s.status = #{status}

ORDER BY s.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM interview_session
WHERE user_id = #{userId}

    AND status = #{status}
